const stdout = ($input.item.json.stdout || '').replace(/EXIT:\d+/, '').trim();
const repos = stdout.split('\n').map(r => r.trim()).filter(Boolean);
const names = repos.map(r => r.split('/').pop());
const ts = new Date().toISOString().slice(0, 16).replace('T', ' ') + ' UTC';
const summary = repos.length > 0
  ? `⚠️ *Git Dirty State Alert* [${ts}]\n\n${names.map(n => `• \`${n}\``).join('\n')}\n\nRun \`git status\` in each repo and commit or stash before next session.`
  : '';
return [{ json: { has_dirty: repos.length > 0, repos, names, summary, checked_at: ts } }];
